async generateRelacion() {
    const dateVal = this.selectedDate;
    if (!dateVal || !/^\d{4}-\d{2}-\d{2}$/.test(dateVal)) {
        alert('Fecha inválida.');
        return;
    }

    // Gather all non-cancelled invoices and sort them according to visual order
    const hasSelected = this.invoices.some(i => i._selected);
    let invoicesToSave = hasSelected 
        ? this.invoices.filter(i => i._selected && i.status !== 'Cancelada')
        : this.invoices.filter(i => i.status !== 'Cancelada');

    invoicesToSave = this.sortInvoicesArray(invoicesToSave);

    if (invoicesToSave.length === 0) {
        alert('No hay facturas para incluir en la relación.');
        return;
    }

    this.relacionLoading = true;
    try {
        const csrfToken = document.querySelector('meta[name="csrf-token"]')?.getAttribute('content') || '';

        // Save the relación to the database (no download)
        const saveRes = await fetch('/orders/api/relaciones', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json', 'X-CSRFToken': csrfToken },
            body: JSON.stringify({ date: dateVal, invoices: invoicesToSave })
        });

        const saveData = await saveRes.json();
        if (!saveRes.ok) {
            alert(saveData.error || 'Error al guardar la relación');
            return;
        }

        this.currentRelacion = saveData.relacion;
        const folio = saveData.relacion.folio;
        const isNew = !this.currentRelacion || saveData.relacion.created_at === saveData.relacion.updated_at;

        // Show success notification
        alert(`✅ Relación ${isNew ? 'generada' : 'actualizada'} exitosamente.\n\nFolio: ${folio}\nFacturas: ${invoicesToSave.length}\n\nRevisa y descarga en la pestaña "Relaciones de Envío".`);

        // Refresh relaciones data
        this.fetchRelacionForDate();
    } catch (e) {
        console.error('Error generating relacion:', e);
        alert('Error de conexión al generar la relación.');
    } finally {
        this.relacionLoading = false;
    }
